import React, { useState, useContext } from 'react';
import { taxasIRT } from '../data/mockData';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Processamento: React.FC = () => {
  const { empresa, colaboradores } = useContext(AppContext);
  const ativos = colaboradores.filter(c => c.status === 'Ativo');
  
  const currentYear = new Date().getFullYear();
  const currentDay = new Date().getDate();
  const [selectedMonth, setSelectedMonth] = useState('Janeiro');
  const [selectedYear, setSelectedYear] = useState(currentYear.toString());
  const [selectedDay, setSelectedDay] = useState(currentDay.toString());



  const [showFormModal, setShowFormModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [selectedColab, setSelectedColab] = useState<Colaborador | null>(null);

  // Form states
  const [formSalario, setFormSalario] = useState(0);
  const [formFaltas, setFormFaltas] = useState(0);
  const [formAlimentacao, setFormAlimentacao] = useState(0);
  const [formTransporte, setFormTransporte] = useState(0);
  const [formFerias, setFormFerias] = useState(0);
  const [outrosSubsidios, setOutrosSubsidios] = useState<{nome: string, valor: number}[]>([]);
  const [tempSubsidioNome, setTempSubsidioNome] = useState('');
  const [tempSubsidioValor, setTempSubsidioValor] = useState(0);
  const [formHorasExtra, setFormHorasExtra] = useState(0);

  const [formBonus, setFormBonus] = useState(0);

  const calcularIRT = (baseSujeitaIRT: number) => {
    const escalao = taxasIRT.find(t => baseSujeitaIRT >= t.minimo && baseSujeitaIRT <= t.maximo);
    if (!escalao) return 0;
    const calc = ((baseSujeitaIRT - escalao.minimo) * (escalao.taxa / 100)) + escalao.parcelaAbt;
    return calc > 0 ? calc : 0;
  };

  const handleStartProcessar = (colab: Colaborador) => {
    setSelectedColab(colab);
    setFormSalario(colab.salarioBase || 0);
    setFormFaltas(0);
    setFormAlimentacao(30000); // Standard defaults
    setFormTransporte(20000);
    setFormFerias(0);
    setOutrosSubsidios([]);
    setFormHorasExtra(0);
    setFormBonus(0);
    setShowFormModal(true);
  };

  const addOutroSubsidio = () => {
    if (tempSubsidioNome && tempSubsidioValor > 0) {
      setOutrosSubsidios([...outrosSubsidios, { nome: tempSubsidioNome, valor: tempSubsidioValor }]);
      setTempSubsidioNome('');
      setTempSubsidioValor(0);
    }
  };

  const removeOutroSubsidio = (index: number) => {
    setOutrosSubsidios(outrosSubsidios.filter((_, i) => i !== index));
  };


  const handleConfirmForm = (e: React.FormEvent) => {
    e.preventDefault();
    setShowFormModal(false);
    setShowReceiptModal(true);
  };

  const currentCalc = () => {
    const totalOutros = outrosSubsidios.reduce((acc, curr) => acc + curr.valor, 0);
    const totalBruto = formSalario + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus;
    const baseSalarioLiquidoFaltas = formSalario - formFaltas;
    
    const taxaINSS = empresa?.taxaINSS || 3;
    const valorINSS = baseSalarioLiquidoFaltas * (taxaINSS / 100);
    const baseIRT = baseSalarioLiquidoFaltas - valorINSS + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus; 
    const valorIRT = calcularIRT(baseIRT);
    
    const totalDescontos = valorINSS + valorIRT + formFaltas;
    const salarioLiquido = totalBruto - totalDescontos;

    return { totalBruto, valorINSS, valorIRT, totalDescontos, salarioLiquido };
  };

  const handleImprimir = () => {
    window.print();
  };

  const handleGuardar = () => {
    const element = document.getElementById('recibo-para-impressao');
    if (!element) return;
    
    // @ts-ignore
    const opt = {
      margin: 0,
      filename: `Recibo_${selectedColab?.nome.replace(/ /g, '_')}_${selectedMonth}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };
    
    // @ts-ignore
    window.html2pdf().from(element).set(opt).save();
  };


  const handleEnviarEmail = () => {
    if(selectedColab?.email) {
      alert(`Recibo enviado para o endereço: ${selectedColab.email}`);
    } else {
      alert('Colaborador não possui um endereço de e-mail registado.');
    }
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black tracking-tight">Processamento de Salários</h2>
          <p className="text-slate-500">Gere a folha de pagamento do período selecionado.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Mês de Referência</label>
          <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2">
            {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Ano</label>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2">
            {['2024', '2025', '2026', '2027'].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Dia de Referência</label>
          <input 
            type="number" 
            min="1" 
            max="31" 
            value={selectedDay} 
            onChange={e => setSelectedDay(e.target.value)} 
            className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2" 
          />
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 flex items-center justify-between">
          <div>
            <p className="text-xs text-slate-500 uppercase font-bold">Status do Processamento</p>
            {empresa?.processamentoAutomatico && Number(selectedDay) <= (empresa.diaProcessamento || 5) ? (
              <p className="text-sm font-medium text-amber-500">Agendado ({empresa.diaProcessamento || 5} de {selectedMonth})</p>
            ) : (
              <p className="text-sm font-medium text-emerald-500">Aberto / Manual</p>
            )}
          </div>
          <span className="material-symbols-outlined text-slate-300">event_available</span>
        </div>
      </div>


      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
              <tr>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Colaborador</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Cargo</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Salário Base</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {ativos.length === 0 ? (
                <tr>
                  <td colSpan={4} className="p-8 text-center text-slate-500">Nenhum colaborador ativo no sistema.</td>
                </tr>
              ) : ativos.map(c => (
                <tr key={c.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="size-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xs uppercase">
                        {c.nome.substring(0, 2)}
                      </div>
                      <div>
                        <p className="text-sm font-semibold">{c.nome}</p>
                        <p className="text-xs text-slate-500">{c.email}</p>
                      </div>
                    </div>
                  </td>
                  <td className="p-4 text-sm">{c.cargo}</td>
                  <td className="p-4 text-right font-medium text-sm">{c.salarioBase.toLocaleString()} Kz</td>
                  <td className="p-4 text-center">
                    <button 
                      onClick={() => handleStartProcessar(c)}
                      className="text-primary border border-primary/20 hover:bg-primary/10 px-4 py-1.5 rounded-lg text-xs font-bold transition-colors"
                    >
                      Processar
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showFormModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60] p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-xl max-w-lg w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-start justify-between bg-slate-50/50 dark:bg-slate-800/20">
              <div>
                <h2 className="font-black text-xl text-slate-900 dark:text-white uppercase tracking-wider">Validar Processamento</h2>
                <div className="text-slate-500 text-sm mt-1">Colaborador: {selectedColab.nome}</div>
              </div>
              <button onClick={() => setShowFormModal(false)} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-lg transition-colors">
                <span className="material-symbols-outlined">close</span>
              </button>
            </div>
            <form onSubmit={handleConfirmForm} className="p-6 space-y-4">
              <div className="space-y-1.5">
                <label className="text-sm font-semibold text-slate-700">Salário Base (Kz)</label>
                <input 
                  required 
                  type="text" 
                  value={formSalario ? formSalario.toLocaleString('pt-AO') : ''} 
                  onChange={e => {
                    const val = e.target.value.replace(/\D/g, '');
                    setFormSalario(val ? Number(val) : 0);
                  }} 
                  onBlur={e => {
                    if (formSalario) {
                      e.target.value = formSalario.toLocaleString('pt-AO', { minimumFractionDigits: 2 }) + ' Kz';
                    }
                  }}
                  placeholder="Ex: 250.000,00 Kz" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary font-bold text-primary" 
                />

              </div>
              
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Alimentação</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formAlimentacao === 0 ? '' : formAlimentacao} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormAlimentacao(val ? Number(val) : 0);
                  }} placeholder="Ex: 30000" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Transporte</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formTransporte === 0 ? '' : formTransporte} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormTransporte(val ? Number(val) : 0);
                  }} placeholder="Ex: 20000" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Férias</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formFerias === 0 ? '' : formFerias} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormFerias(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
              </div>

              <div className="p-4 bg-slate-50 border border-slate-200 rounded-xl space-y-3">
                <label className="text-sm font-bold text-slate-800 flex items-center gap-2">
                  <span className="material-symbols-outlined text-primary text-sm">add_circle</span>
                  Outros Subsídios
                </label>
                
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Nome do subsídio" 
                    value={tempSubsidioNome}
                    onChange={e => setTempSubsidioNome(e.target.value)}
                    className="flex-1 px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-sm"
                  />
                  <input 
                    type="text" 
                    placeholder="Valor" 
                    value={tempSubsidioValor || ''}
                    onChange={e => setTempSubsidioValor(Number(e.target.value.replace(/\D/g, '')))}
                    className="w-24 px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-sm"
                  />
                  <button 
                    type="button"
                    onClick={addOutroSubsidio}
                    className="px-3 py-1.5 bg-primary text-white rounded-lg text-xs font-bold"
                  >
                    Add
                  </button>
                </div>

                {outrosSubsidios.length > 0 && (
                  <div className="space-y-2 max-h-32 overflow-y-auto pt-2">
                    {outrosSubsidios.map((s, idx) => (
                      <div key={idx} className="flex items-center justify-between bg-white px-3 py-1.5 rounded-lg border border-slate-100 text-xs shadow-sm">
                        <span className="font-medium">{s.nome}</span>
                        <div className="flex items-center gap-3">
                          <span className="font-bold text-primary">{s.valor.toLocaleString()} Kz</span>
                          <button onClick={() => removeOutroSubsidio(idx)} className="text-red-500 hover:text-red-700">
                            <span className="material-symbols-outlined text-sm">delete</span>
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-green-700">Horas Extra</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formHorasExtra === 0 ? '' : formHorasExtra} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormHorasExtra(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-green-50 border border-green-200 rounded-lg outline-none focus:border-green-400" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-green-700">Bónus/Prémio</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formBonus === 0 ? '' : formBonus} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormBonus(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-green-50 border border-green-200 rounded-lg outline-none focus:border-green-400" />
                </div>
              </div>


              <div className="pt-4 border-t border-slate-100">
                <div className="space-y-1.5 flex flex-col">
                  <label className="text-sm font-semibold text-red-600 flex items-center gap-1"><span className="material-symbols-outlined text-[16px]">warning</span> Faltas (Valor a descontar)</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formFaltas === 0 ? '' : formFaltas} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormFaltas(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-red-50 border border-red-200 text-red-700 rounded-lg outline-none focus:border-red-400" />
                </div>
              </div>
              
              <button type="submit" className="w-full mt-4 py-3 bg-primary text-white rounded-lg font-bold hover:bg-primary/90 flex items-center justify-center gap-2">
                <span className="material-symbols-outlined">calculate</span>
                Processar
              </button>
            </form>
          </div>
        </div>
      )}

      {showReceiptModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl max-w-[210mm] w-full max-h-[95vh] overflow-y-auto shadow-2xl">
            <style>
              {`
                @media print {
                  body * { visibility: hidden; }
                  #recibo-para-impressao, #recibo-para-impressao * { visibility: visible; }
                  #recibo-para-impressao {
                    position: absolute;
                    left: 0;
                    top: 0;
                    width: 210mm;
                    height: 297mm;
                    padding: 20mm;
                    margin: 0;
                    background: white;
                  }
                  .no-print { display: none !important; }
                }
              `}
            </style>
            <div className="p-10 bg-white" id="recibo-para-impressao" style={{ minHeight: '297mm', boxSizing: 'border-box' }}>
              
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', borderBottom: '3px solid #1162d4', paddingBottom: '20px', marginBottom: '30px' }}>
                <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
                  <img src="/logo.png" alt="Logo" style={{ width: '80px', height: '80px', objectFit: 'contain' }} />
                  <div style={{ textAlign: 'left' }}>
                    <h1 style={{ fontSize: '20pt', fontWeight: '900', color: '#1162d4', margin: '0' }}>{empresa?.nome || 'EMPRESA'}</h1>
                    <p style={{ fontSize: '10pt', color: '#666', margin: '5px 0' }}>NIF: {empresa?.nif || '-'}</p>
                    <p style={{ fontSize: '9pt', color: '#666', maxWidth: '300px' }}>{empresa?.endereco || ''}</p>
                  </div>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <h2 style={{ fontSize: '14pt', fontWeight: '900', color: '#333', margin: '0 0 10px 0' }}>RECIBO DE SALÁRIO</h2>
                  <div style={{ background: '#f8fafc', border: '1px solid #e2e8f0', padding: '10px 20px', borderRadius: '8px' }}>
                    <p style={{ fontSize: '10pt', fontWeight: 'bold', margin: '0' }}>Período: {selectedMonth} / {selectedYear}</p>
                    <p style={{ fontSize: '9pt', color: '#64748b', margin: '5px 0 0 0' }}>Data: {selectedDay} / {selectedMonth}</p>
                  </div>
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '30px', marginBottom: '30px', background: '#fcfcfc', border: '1px solid #f0f0f0', padding: '20px', borderRadius: '12px' }}>
                <div>
                  <h3 style={{ fontSize: '9pt', fontWeight: 'bold', color: '#1162d4', textTransform: 'uppercase', marginBottom: '10px', borderBottom: '1px solid #1162d4' }}>DADOS DO FUNCIONÁRIO</h3>
                  <p style={{ fontSize: '11pt', fontWeight: 'bold', margin: '5px 0' }}>{selectedColab.nome}</p>
                  <p style={{ fontSize: '10pt', margin: '3px 0' }}>ID: {selectedColab.numeroColaborador || '-'}</p>
                  <p style={{ fontSize: '10pt', margin: '3px 0' }}>Cargo: {selectedColab.cargo}</p>
                  <p style={{ fontSize: '10pt', margin: '3px 0' }}>Contrato: {selectedColab.tipoContrato || '-'}</p>
                  <p style={{ fontSize: '10pt', margin: '3px 0' }}>Admissão: {selectedColab.dataAdmissao || '-'}</p>
                </div>
                <div>
                  <h3 style={{ fontSize: '9pt', fontWeight: 'bold', color: '#1162d4', textTransform: 'uppercase', marginBottom: '10px', borderBottom: '1px solid #1162d4' }}>INFORMAÇÃO BANCÁRIA / FISCAL</h3>
                  <p style={{ fontSize: '10pt', margin: '5px 0' }}><strong>NIF:</strong> {selectedColab.nif}</p>
                  <p style={{ fontSize: '10pt', margin: '5px 0' }}><strong>Nº INSS:</strong> {selectedColab.inss || '-'}</p>
                  <p style={{ fontSize: '10pt', margin: '5px 0' }}><strong>Banco:</strong> {selectedColab.banco || '-'}</p>
                  <p style={{ fontSize: '11pt', margin: '8px 0', padding: '5px', background: '#dbeafe', borderRadius: '4px', fontWeight: 'bold', color: '#1d4ed8' }}>IBAN: {selectedColab.iban || '-'}</p>
                </div>
              </div>

              <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: '30px' }}>
                <thead>
                  <tr style={{ background: '#1162d4', color: 'white' }}>
                    <th style={{ padding: '12px', textAlign: 'left', fontSize: '10pt', borderTopLeftRadius: '8px' }}>DESCRIÇÃO</th>
                    <th style={{ padding: '12px', textAlign: 'right', fontSize: '10pt', borderTopRightRadius: '8px' }}>VALOR (Kz)</th>
                  </tr>
                </thead>
                <tbody style={{ border: '1px solid #e2e8f0' }}>
                  <tr>
                    <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Vencimento Base</td>
                    <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{formSalario.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                  </tr>
                  {formAlimentacao > 0 && (
                    <tr>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Subsídio Alimentação</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{formAlimentacao.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  )}
                  {formTransporte > 0 && (
                    <tr>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Subsídio Transporte</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{formTransporte.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  )}
                  {formFerias > 0 && (
                    <tr>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Subsídio Férias</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{formFerias.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  )}
                  {outrosSubsidios.map((s, idx) => (
                    <tr key={idx}>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>{s.nome}</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{s.valor.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  ))}
                  {formHorasExtra > 0 && (
                    <tr>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Horas Extra</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{formHorasExtra.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  )}
                  {formBonus > 0 && (
                    <tr>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Bónus / Prémio</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', fontSize: '10pt' }}>{formBonus.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  )}
                  <tr style={{ background: '#f8fafc', fontWeight: 'bold' }}>
                    <td style={{ padding: '12px', fontSize: '10pt' }}>TOTAL BRUTO</td>
                    <td style={{ padding: '12px', textAlign: 'right', fontSize: '11pt' }}>{currentCalc().totalBruto.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                  </tr>
                  
                  <tr><td colSpan={2} style={{ padding: '15px 0 5px 0', fontSize: '9pt', fontWeight: 'bold', color: '#64748b' }}>DEDUÇÕES</td></tr>
                  
                  <tr>
                    <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Segurança Social (SS {empresa?.taxaINSS || 3}%)</td>
                    <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', color: '#ef4444', fontSize: '10pt' }}>- {currentCalc().valorINSS.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                  </tr>
                  <tr>
                    <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Imposto sobre Rendimento (IRT)</td>
                    <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', color: '#ef4444', fontSize: '10pt' }}>- {currentCalc().valorIRT.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                  </tr>
                  {formFaltas > 0 && (
                    <tr>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', fontSize: '10pt' }}>Faltas</td>
                      <td style={{ padding: '10px 12px', borderBottom: '1px solid #f1f5f9', textAlign: 'right', color: '#ef4444', fontSize: '10pt' }}>- {formFaltas.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                    </tr>
                  )}
                  <tr style={{ background: '#fef2f2', fontWeight: 'bold', color: '#ef4444' }}>
                    <td style={{ padding: '12px', fontSize: '10pt' }}>TOTAL DEDUÇÕES</td>
                    <td style={{ padding: '12px', textAlign: 'right', fontSize: '11pt' }}>- {currentCalc().totalDescontos.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td>
                  </tr>
                </tbody>
              </table>

              <div style={{ background: '#1162d4', padding: '25px', borderRadius: '12px', color: 'white', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
                <span style={{ fontSize: '14pt', fontWeight: 'bold' }}>VALOR LÍQUIDO A RECEBER</span>
                <span style={{ fontSize: '24pt', fontWeight: '900' }}>{currentCalc().salarioLiquido.toLocaleString('pt-AO', { minimumFractionDigits: 2 })} Kz</span>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '50px', marginTop: '60px', textAlign: 'center' }}>
                <div>
                  <div style={{ borderBottom: '1px solid #333', marginBottom: '10px', height: '40px' }}></div>
                  <p style={{ fontSize: '9pt', fontWeight: 'bold' }}>ENTIDADE EMPREGADORA</p>
                </div>
                <div>
                  <div style={{ borderBottom: '1px solid #333', marginBottom: '10px', height: '40px' }}></div>
                  <p style={{ fontSize: '9pt', fontWeight: 'bold' }}>LI E RECEBI EM CONFORME</p>
                </div>
              </div>

              <div style={{ marginTop: 'auto', paddingTop: '40px', textAlign: 'center', borderTop: '1px solid #e2e8f0' }}>
                <p style={{ fontSize: '8pt', color: '#94a3b8' }}>Este documento é um recibo de vencimento oficial gerado pelo sistema SALYA.</p>
                <p style={{ fontSize: '7pt', color: '#cbd5e1', marginTop: '5px' }}>ID de Processamento: {Date.now()}</p>
              </div>
            </div>
            
            <div className="p-6 border-t border-slate-200 bg-slate-50 flex gap-3 no-print">
              <button onClick={handleGuardar} className="flex-1 py-3 bg-primary text-white rounded-lg font-bold hover:bg-primary/90 flex items-center justify-center gap-2 shadow-lg shadow-primary/20">
                <span className="material-symbols-outlined">picture_as_pdf</span> Guardar PDF
              </button>
              <button onClick={handleImprimir} className="flex-1 py-3 bg-white text-slate-700 border border-slate-300 rounded-lg font-bold hover:bg-slate-50 flex items-center justify-center gap-2">
                <span className="material-symbols-outlined">print</span> Imprimir
              </button>
              <button onClick={() => setShowReceiptModal(false)} className="px-6 py-3 bg-slate-200 text-slate-600 rounded-lg font-bold hover:bg-slate-300">
                Fechar
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default Processamento;
